import{_ as a,o as n,c as t,a2 as s}from"./chunks/framework.CuteRReP.js";const m=JSON.parse('{"title":"cm-terminal","description":"Use when running ANY terminal command - enforces clear progress logging, output reading, and error-stop behavior so terminal processes are never left unchecked","frontmatter":{"title":"cm-terminal","description":"Use when running ANY terminal command - enforces clear progress logging, output reading, and error-stop behavior so terminal processes are never left unchecked","keywords":["cm-terminal","cody master","ai skill"],"robots":"index, follow"},"headers":[],"relativePath":"skills/cm-terminal.md","filePath":"skills/cm-terminal.md"}'),o={name:"skills/cm-terminal.md"};function r(i,e,l,d,p,c){return n(),t("div",null,[...e[0]||(e[0]=[s(`<blockquote><p><strong>📋 Full Skill Source</strong> — This is the complete, unedited SKILL.md file. Nothing is hidden or summarized.</p></blockquote><p><a href="./">← Back to Skills Library</a></p><h1 id="terminal-process-monitoring" tabindex="-1">Terminal Process Monitoring <a class="header-anchor" href="#terminal-process-monitoring" aria-label="Permalink to &quot;Terminal Process Monitoring&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Running commands without checking output is flying blind. Users MUST see what&#39;s happening at every step.</p><p><strong>Core principle:</strong> Every command gets announced, monitored, and verified. No exceptions.</p><p><strong>Violating the letter of this rule is violating the spirit of this rule.</strong></p><h2 id="the-iron-law" tabindex="-1">The Iron Law <a class="header-anchor" href="#the-iron-law" aria-label="Permalink to &quot;The Iron Law&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NO COMMAND RUNS WITHOUT READING ITS OUTPUT.</span></span>
<span class="line"><span>NO ERROR GOES UNREPORTED.</span></span>
<span class="line"><span>NO NEXT STEP WITHOUT PREVIOUS STEP CONFIRMED.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="when-to-use" tabindex="-1">When to Use <a class="header-anchor" href="#when-to-use" aria-label="Permalink to &quot;When to Use&quot;">​</a></h2><p><strong>ALWAYS</strong> when running terminal commands via <code>run_command</code>. This includes:</p><ul><li>Build commands (<code>npm run build</code>, <code>npm run dev</code>)</li><li>Test commands (<code>npx vitest run</code>)</li><li>Install commands (<code>npm install</code>)</li><li>Deploy commands (<code>npx wrangler pages deploy</code>)</li><li>Git commands (<code>git push</code>, <code>git commit</code>)</li><li>Any script or CLI tool</li></ul><h2 id="the-protocol" tabindex="-1">The Protocol <a class="header-anchor" href="#the-protocol" aria-label="Permalink to &quot;The Protocol&quot;">​</a></h2><h3 id="step-1-announce-before-running" tabindex="-1">Step 1: Announce Before Running <a class="header-anchor" href="#step-1-announce-before-running" aria-label="Permalink to &quot;Step 1: Announce Before Running&quot;">​</a></h3><p><strong>BEFORE calling <code>run_command</code>:</strong></p><p>Update <code>task_boundary</code> TaskStatus to describe what you&#39;re about to run and why.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>TaskStatus: &quot;Running npm build to compile production bundle&quot;</span></span>
<span class="line"><span>TaskStatus: &quot;Installing dependencies with npm install&quot;</span></span>
<span class="line"><span>TaskStatus: &quot;Deploying to Cloudflare Pages&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="step-2-set-appropriate-wait-time" tabindex="-1">Step 2: Set Appropriate Wait Time <a class="header-anchor" href="#step-2-set-appropriate-wait-time" aria-label="Permalink to &quot;Step 2: Set Appropriate Wait Time&quot;">​</a></h3><p>Choose <code>WaitMsBeforeAsync</code> based on expected command duration:</p><table tabindex="0"><thead><tr><th>Command Type</th><th>WaitMsBeforeAsync</th><th>Strategy</th></tr></thead><tbody><tr><td>Quick (&lt; 3s) — <code>git status</code>, <code>ls</code>, <code>cat</code></td><td>3000-5000</td><td>Synchronous, read output directly</td></tr><tr><td>Medium (3-30s) — <code>npm install</code>, <code>build</code></td><td>5000-10000</td><td>Wait for initial output, then poll</td></tr><tr><td>Long (&gt; 30s) — <code>deploy</code>, <code>test suites</code></td><td>2000-5000</td><td>Send to background, poll actively</td></tr></tbody></table><h3 id="step-3-read-output-immediately" tabindex="-1">Step 3: Read Output Immediately <a class="header-anchor" href="#step-3-read-output-immediately" aria-label="Permalink to &quot;Step 3: Read Output Immediately&quot;">​</a></h3><p><strong>After <code>run_command</code> returns:</strong></p><ol><li>If command completed synchronously → read output in the response</li><li>If command sent to background → call <code>command_status</code> immediately with <code>WaitDurationSeconds: 10</code></li><li><strong>NEVER proceed to next step without reading output</strong></li></ol><h3 id="step-4-check-for-errors" tabindex="-1">Step 4: Check for Errors <a class="header-anchor" href="#step-4-check-for-errors" aria-label="Permalink to &quot;Step 4: Check for Errors&quot;">​</a></h3><p>Scan output for error indicators:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ERROR PATTERNS TO DETECT:</span></span>
<span class="line"><span>- Exit code ≠ 0</span></span>
<span class="line"><span>- &quot;error&quot;, &quot;Error&quot;, &quot;ERROR&quot;</span></span>
<span class="line"><span>- &quot;fail&quot;, &quot;FAIL&quot;, &quot;failed&quot;, &quot;FAILED&quot;</span></span>
<span class="line"><span>- &quot;ENOENT&quot;, &quot;EACCES&quot;, &quot;EPERM&quot;</span></span>
<span class="line"><span>- &quot;not found&quot;, &quot;No such file&quot;</span></span>
<span class="line"><span>- &quot;Cannot find module&quot;</span></span>
<span class="line"><span>- &quot;SyntaxError&quot;, &quot;TypeError&quot;, &quot;ReferenceError&quot;</span></span>
<span class="line"><span>- &quot;Build failed&quot;</span></span>
<span class="line"><span>- &quot;Command failed&quot;</span></span>
<span class="line"><span>- &quot;Permission denied&quot;</span></span>
<span class="line"><span>- &quot;FATAL&quot;</span></span>
<span class="line"><span>- Stack traces (lines with &quot;at &quot; prefix)</span></span>
<span class="line"><span>- npm ERR!</span></span>
<span class="line"><span>- Warning patterns that indicate real problems</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><h3 id="step-5-stop-on-error" tabindex="-1">Step 5: Stop on Error <a class="header-anchor" href="#step-5-stop-on-error" aria-label="Permalink to &quot;Step 5: Stop on Error&quot;">​</a></h3><p><strong>If ANY error is detected:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. STOP — Do not run any more commands</span></span>
<span class="line"><span>2. IDENTIFY — Extract the exact error message and context</span></span>
<span class="line"><span>3. REPORT — Call notify_user with error if critical</span></span>
<span class="line"><span>4. FIX — Use cm-debugging if proceeding to fix</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="step-6-poll-long-running-commands" tabindex="-1">Step 6: Poll Long-Running Commands <a class="header-anchor" href="#step-6-poll-long-running-commands" aria-label="Permalink to &quot;Step 6: Poll Long-Running Commands&quot;">​</a></h3><p><strong>For background commands (returned a CommandId):</strong></p><ol><li>Poll <code>command_status</code> every 10-15 seconds</li><li>After EACH poll, update <code>task_boundary</code> TaskStatus with latest output summary</li><li>Continue until command completes (status: &quot;done&quot;)</li><li>Read final output and check for errors</li></ol><h3 id="step-7-confirm-success" tabindex="-1">Step 7: Confirm Success <a class="header-anchor" href="#step-7-confirm-success" aria-label="Permalink to &quot;Step 7: Confirm Success&quot;">​</a></h3><p><strong>Only after reading output AND confirming no errors:</strong></p><p>Update <code>task_boundary</code> TaskSummary with the result:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>TaskSummary: &quot;Build completed successfully (0 errors, 0 warnings)&quot;</span></span>
<span class="line"><span>TaskSummary: &quot;All 519 tests passed&quot;</span></span>
<span class="line"><span>TaskSummary: &quot;Deployed to https://prms-4pv.pages.dev successfully&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="red-flags-—-stop-and-follow-protocol" tabindex="-1">Red Flags — STOP and Follow Protocol <a class="header-anchor" href="#red-flags-—-stop-and-follow-protocol" aria-label="Permalink to &quot;Red Flags — STOP and Follow Protocol&quot;">​</a></h2><p>If you catch yourself doing ANY of these:</p><ul><li>Running a command without updating TaskStatus first</li><li>Calling <code>run_command</code> while previous command is still running</li><li>Skipping <code>command_status</code> for a background command</li><li>Proceeding to next step without reading output</li><li>Ignoring warnings or errors in output</li><li>Assuming a command succeeded without checking exit code</li><li>Running 3+ commands in parallel without monitoring each</li></ul><p><strong>ALL of these mean: STOP. Follow the protocol.</strong></p><h2 id="anti-patterns" tabindex="-1">Anti-Patterns <a class="header-anchor" href="#anti-patterns" aria-label="Permalink to &quot;Anti-Patterns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>DON&#39;T</th><th>DO</th></tr></thead><tbody><tr><td>Run and forget</td><td>Run and read output</td></tr><tr><td>Assume success</td><td>Verify success from output</td></tr><tr><td>Chain commands blindly</td><td>Verify each before next</td></tr><tr><td>Ignore warnings</td><td>Report warnings to user</td></tr><tr><td>Multiple commands without checking</td><td>Sequential with verification</td></tr></tbody></table><h2 id="special-cases" tabindex="-1">Special Cases <a class="header-anchor" href="#special-cases" aria-label="Permalink to &quot;Special Cases&quot;">​</a></h2><h3 id="interactive-commands-dev-servers-watch-mode" tabindex="-1">Interactive Commands (dev servers, watch mode) <a class="header-anchor" href="#interactive-commands-dev-servers-watch-mode" aria-label="Permalink to &quot;Interactive Commands (dev servers, watch mode)&quot;">​</a></h3><ol><li>Start with <code>WaitMsBeforeAsync: 3000-5000</code></li><li>Check initial output for startup success/failure</li><li>Look for &quot;ready&quot; / &quot;listening on&quot; / &quot;compiled successfully&quot; signals</li><li>Report the URL/port to user</li><li>Note the CommandId for future reference</li></ol><h3 id="parallel-commands" tabindex="-1">Parallel Commands <a class="header-anchor" href="#parallel-commands" aria-label="Permalink to &quot;Parallel Commands&quot;">​</a></h3><p>If running multiple commands at once:</p><ol><li>Track ALL CommandIds</li><li>Poll each one separately</li><li>If ANY fails → report which one failed</li></ol><h3 id="piped-chained-commands" tabindex="-1">Piped/Chained Commands (<code>&amp;&amp;</code>, <code>|</code>) <a class="header-anchor" href="#piped-chained-commands" aria-label="Permalink to &quot;Piped/Chained Commands (\`&amp;&amp;\`, \`|\`)&quot;">​</a></h3><ol><li>The exit code reflects the LAST command in the chain</li><li>Read full output — errors from earlier commands may appear but the chain continues</li><li>Be extra careful with <code>cd dir &amp;&amp; npm run build</code> — if <code>cd</code> fails, build won&#39;t run</li></ol><h2 id="severity-levels" tabindex="-1">Severity Levels <a class="header-anchor" href="#severity-levels" aria-label="Permalink to &quot;Severity Levels&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Level</th><th>Action</th><th>Example</th></tr></thead><tbody><tr><td>🟢 <strong>Success</strong></td><td>Update TaskSummary, proceed</td><td>&quot;Build succeeded&quot;</td></tr><tr><td>🟡 <strong>Warning</strong></td><td>Report to user, ask if proceed</td><td>&quot;Deprecated dependency&quot;</td></tr><tr><td>🔴 <strong>Error</strong></td><td>STOP immediately, notify_user or fix</td><td>&quot;Build failed&quot;, &quot;Test failed&quot;</td></tr><tr><td>⚫ <strong>Fatal</strong></td><td>STOP immediately, notify_user</td><td>&quot;ENOENT&quot;, &quot;Permission denied&quot;</td></tr></tbody></table><h2 id="the-bottom-line" tabindex="-1">The Bottom Line <a class="header-anchor" href="#the-bottom-line" aria-label="Permalink to &quot;The Bottom Line&quot;">​</a></h2><p><strong>Every command tells a story through its output. READ the story. SHARE it with the user. STOP if the story is bad.</strong></p>`,54)])])}const h=a(o,[["render",r]]);export{m as __pageData,h as default};
